import React, { useState, useEffect } from 'react';
import CourseCard from '../components/CourseCard';
import config, { getAllCourses } from '../config/config';
import { 
  getFeaturedCourses, 
  getStats, 
  checkHealth,
  addSampleCourses 
} from '../services/api';
import { useNavigate } from 'react-router-dom';

const Home = () => {
  const [searchQuery, setSearchQuery] = useState('');
  const [backendCourses, setBackendCourses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [backendStatus, setBackendStatus] = useState('checking');
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);
  const [latestMaterials, setLatestMaterials] = useState([]);
  const [materialsLoading, setMaterialsLoading] = useState(true);
  const [materialsError, setMaterialsError] = useState('');
  const [showAddCoursesBtn, setShowAddCoursesBtn] = useState(false);
  const [stats, setStats] = useState([]);

  const navigate = useNavigate();
  const staticCourses = getAllCourses();

  useEffect(() => {
    const handleResize = () => setWindowWidth(window.innerWidth);
    window.addEventListener('resize', handleResize);
    checkBackend();
    fetchData();
    fetchLatestMaterials();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- API Functions (Keep your existing logic) ---
  const fetchLatestMaterials = async () => {
    try {
      setMaterialsLoading(true);
      const response = await fetch('http://localhost:5000/api/materials');
      const data = await response.json();
      if (data.success) setLatestMaterials(data.materials.slice(0, 6));
    } catch (error) {
      setMaterialsError('Backend offline');
    } finally {
      setMaterialsLoading(false);
    }
  };

  const checkBackend = async () => {
    try {
      const health = await checkHealth();
      setBackendStatus('connected');
      if (health.course_count === 0) setShowAddCoursesBtn(true);
    } catch (error) {
      setBackendStatus('disconnected');
    }
  };

  const fetchData = async () => {
    try {
      const coursesData = await getFeaturedCourses(6);
      const transformedCourses = coursesData.courses.map(course => ({
        ...course,
        branch: course.branch || 'General',
        semester: course.semester || 'All'
      }));
      setBackendCourses(transformedCourses);
      const statsData = await getStats();
      updateStats(statsData);
    } catch (error) {
      updateStats(null);
      setBackendStatus('disconnected');
    } finally {
      setLoading(false);
    }
  };

  const updateStats = (data) => {
    const defaults = config.STATS_DEFAULTS;
    setStats([
      { title: 'Notes', value: `${data?.totalNotes || defaults.totalNotes}+`, icon: '📚', color: '#4F46E5' },
      { title: 'PYQs', value: `${data?.totalPYQs || defaults.totalPYQs}+`, icon: '✍️', color: '#7C3AED' },
      { title: 'Courses', value: `${data?.totalCourses || defaults.totalCourses}+`, icon: '🎓', color: '#EC4899' },
      { title: 'Active Users', value: '2K+', icon: '👥', color: '#10B981' },
    ]);
  };

  const handleSearch = () => {
    if (searchQuery.trim()) navigate(`/search?q=${encodeURIComponent(searchQuery)}`);
  };

  const handleMaterialClick = (material) => {
    const url = material.source === 'notes' 
      ? `http://localhost:5000/download/notes/${material.id}`
      : `http://localhost:5000/download/materials/${material.id}`;
    window.open(url, '_blank');
  };

  const displayCourses = backendStatus === 'connected' && backendCourses.length > 0 
    ? backendCourses : staticCourses;

  // --- New Modern Styles ---
  const theme = {
    primary: 'linear-gradient(135deg, #6366f1 0%, #a855f7 100%)',
    glass: 'rgba(255, 255, 255, 0.9)',
    cardShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1), 0 8px 10px -6px rgba(0, 0, 0, 0.1)',
    hoverShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.2)',
  };

  const styles = {
    hero: {
      padding: '6rem 1rem',
      background: theme.primary,
      borderRadius: '0 0 50px 50px',
      color: 'white',
      textAlign: 'center',
      position: 'relative',
      overflow: 'hidden'
    },
    searchBox: {
      background: 'white',
      padding: '8px',
      borderRadius: '50px',
      display: 'flex',
      maxWidth: '700px',
      margin: '2rem auto',
      boxShadow: '0 10px 30px rgba(0,0,0,0.2)',
    },
    input: {
      border: 'none',
      padding: '12px 25px',
      flex: 1,
      borderRadius: '50px',
      fontSize: '1.1rem',
      outline: 'none'
    },
    btnPrimary: {
      background: '#1f2937',
      color: 'white',
      border: 'none',
      padding: '12px 30px',
      borderRadius: '50px',
      fontWeight: '600',
      cursor: 'pointer',
      transition: 'transform 0.2s'
    },
    statCard: {
      background: 'white',
      padding: '2rem 1.5rem',
      borderRadius: '24px',
      boxShadow: theme.cardShadow,
      border: '1px solid #f1f5f9',
      transition: 'all 0.3s ease',
      cursor: 'default'
    },
    materialCard: {
      background: 'white',
      borderRadius: '20px',
      padding: '1.5rem',
      border: '1px solid #e2e8f0',
      transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
      boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'space-between'
    },
    badge: (type) => ({
      padding: '4px 12px',
      borderRadius: '10px',
      fontSize: '0.75rem',
      fontWeight: 'bold',
      width: 'fit-content',
      marginBottom: '1rem',
      background: type === 'pyq' ? '#FEF3C7' : '#DBEAFE',
      color: type === 'pyq' ? '#92400E' : '#1E40AF'
    })
  };

  return (
    <div style={{ backgroundColor: '#f8fafc', minHeight: '100vh', fontFamily: "'Inter', sans-serif" }}>
      
      {/* Hero Section */}
      <section style={styles.hero}>
        <div style={{ position: 'absolute', top: 20, right: 20 }}>
          <span style={{ 
            background: backendStatus === 'connected' ? '#10b981' : '#ef4444',
            padding: '6px 16px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: '600'
          }}>
            ● {backendStatus === 'connected' ? 'Systems Online' : 'Offline Mode'}
          </span>
        </div>
        
        <h1 style={{ fontSize: windowWidth < 768 ? '2.5rem' : '4rem', fontWeight: '800', letterSpacing: '-1px' }}>
          Master Your <span style={{ color: '#fcd34d' }}>Studies</span>
        </h1>
        <p style={{ fontSize: '1.2rem', opacity: 0.9, maxWidth: '700px', margin: '1rem auto' }}>
          Access premium notes, previous year questions, and structured courses all in one place.
        </p>

        <div style={styles.searchBox}>
          <input 
            style={styles.input} 
            placeholder="What are you looking for today?" 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
          />
          <button style={styles.btnPrimary} onClick={handleSearch}>Search</button>
        </div>
      </section>

      {/* Stats Section */}
      <div style={{ maxWidth: '1200px', margin: '-50px auto 4rem', padding: '0 1rem' }}>
        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: windowWidth < 768 ? 'repeat(2, 1fr)' : 'repeat(4, 1fr)', 
          gap: '1.5rem' 
        }}>
          {stats.map((stat, i) => (
            <div key={i} style={styles.statCard} onMouseEnter={(e) => e.currentTarget.style.transform = 'translateY(-10px)'} onMouseLeave={(e) => e.currentTarget.style.transform = 'translateY(0)'}>
              <div style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>{stat.icon}</div>
              <div style={{ fontSize: '1.8rem', fontWeight: '800', color: '#1f2937' }}>{stat.value}</div>
              <div style={{ color: '#64748b', fontWeight: '500' }}>{stat.title}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Latest Materials - Modern List */}
      <section style={{ maxWidth: '1200px', margin: '0 auto 4rem', padding: '0 1rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '2rem' }}>
          <div>
            <h2 style={{ fontSize: '2rem', fontWeight: '800', color: '#1f2937' }}>Recent Uploads</h2>
            <p style={{ color: '#64748b' }}>Freshly added resources from your community</p>
          </div>
          <button onClick={() => navigate('/materials')} style={{ color: '#6366f1', fontWeight: '600', border: 'none', background: 'none', cursor: 'pointer' }}>
            View All →
          </button>
        </div>

        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: windowWidth < 1024 ? (windowWidth < 768 ? '1fr' : 'repeat(2, 1fr)') : 'repeat(3, 1fr)', 
          gap: '1.5rem' 
        }}>
          {latestMaterials.map((m) => (
            <div key={m.id} style={styles.materialCard} onClick={() => handleMaterialClick(m)}>
              <div>
                <div style={styles.badge(m.material_type || m.note_type)}>
                  {(m.material_type || m.note_type || 'Note').toUpperCase()}
                </div>
                <h4 style={{ fontSize: '1.2rem', fontWeight: '700', marginBottom: '0.5rem', color: '#1e293b' }}>{m.title}</h4>
                <div style={{ display: 'flex', gap: '10px', fontSize: '0.85rem', color: '#64748b' }}>
                  <span>🎓 {m.course_name}</span>
                  <span>👤 {m.user_name}</span>
                </div>
              </div>
              <div style={{ marginTop: '1.5rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span style={{ fontSize: '0.8rem', color: '#94a3b8' }}>{new Date(m.uploaded_at).toLocaleDateString()}</span>
                <button style={{ background: '#f1f5f9', border: 'none', padding: '8px 16px', borderRadius: '12px', fontWeight: '600', color: '#475569', cursor: 'pointer' }}>
                  Download
                </button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Featured Courses Section */}
      <section style={{ maxWidth: '1200px', margin: '0 auto 4rem', padding: '0 1rem' }}>
        <h2 style={{ fontSize: '2rem', fontWeight: '800', color: '#1f2937', marginBottom: '2rem', textAlign: 'center' }}>Browse by Category</h2>
        <div style={{ 
          display: 'grid', 
          gridTemplateColumns: windowWidth < 1024 ? (windowWidth < 768 ? '1fr' : 'repeat(2, 1fr)') : 'repeat(3, 1fr)', 
          gap: '2rem' 
        }}>
          {displayCourses.map(course => (
            <div key={course.id} onClick={() => navigate(`/course/${course.id}`)} style={{ cursor: 'pointer' }}>
               <CourseCard course={course} />
            </div>
          ))}
        </div>
      </section>
      
    </div>
  );
};

export default Home;
